const body = $json.body || $json || {};
const proxy = (body.proxy && typeof body.proxy === 'object') ? body.proxy : {};
const purpose = String(body.proxy_purpose || body.purpose || 'WA_REGISTRATION').trim();
const seed = `${$execution.id}-${Date.now()}-${Math.random().toString(16).slice(2)}`;
const proxyStateJSON = String(body.proxy_state_json || body.state_json || proxy.proxy_state_json || proxy.state_json || '').trim();
const proxyURL = String(body.proxy_url || proxy.proxy_url || '').trim();
return [{ json: {
  workspace_id: body.workspace_id || 'default',
  job_id: body.job_id || $execution.id,
  request_id: body.request_id || $execution.id,
  purpose,
  account_id: `wa-us-dyn-${seed}`.slice(0, 120),
  selection_seed: seed,
  provided_proxy: Boolean(proxyURL || proxyStateJSON),
  proxy_url: proxyURL,
  proxy_state_json: proxyStateJSON,
} }];

function parseJSON(value) { try { return JSON.parse(String(value || '{}')); } catch { return {}; } }
const input = $('Normalize Dynamic IP Input').first().json;
const state = parseJSON(input.proxy_state_json);
const proxyURL = input.proxy_url || state._gopay_proxy || state.proxy_url || '';
const accountID = state._proxy_runtime_account_id || state.proxy_account_id || input.account_id || '';
const leaseID = state._proxy_runtime_lease_id || state.proxy_lease_id || '';
return [{ json: {
  success: Boolean(proxyURL || input.proxy_state_json),
  accepted: Boolean(proxyURL || input.proxy_state_json),
  proxy_mode: 'SHARED_DYNAMIC_IP',
  country_code: state._gopay_country_code || state.country_code || '',
  account_id: accountID,
  lease_id: leaseID,
  proxy_url: proxyURL,
  proxy_state_json: input.proxy_state_json,
} }];

const input = $('Normalize Dynamic IP Input').first().json;
const response = $('Acquire US Dynamic IP').first().json || {};
const statusCode = response.statusCode || response.status || 200;
const body = response.body || response || {};
if (statusCode < 200 || statusCode >= 300) {
  return [{ json: { success: false, accepted: false, proxy_mode: 'US_RANDOM_DYNAMIC_IP', country_code: 'US', account_id: input.account_id, error_message: `proxy-runtime dynamic IP acquire returned HTTP ${statusCode}` } }];
}
const lease = body.lease || {};
const egress = body.egress || lease.egress || {};
function runtimeHost() {
  const base = String($env.PROXY_RUNTIME_API_BASE_URL || '').trim();
  try { return new URL(base).hostname || 'proxy-runtime'; } catch { return 'proxy-runtime'; }
}
function endpointScheme(endpoint) {
  return String(endpoint.protocol || '').toUpperCase().includes('SOCKS5') ? 'socks5' : 'http';
}
function endpointHost(endpoint) {
  const host = String(endpoint.host || '').trim();
  if (!host || host === '0.0.0.0' || host === '127.0.0.1' || host === 'localhost' || host === '::' || host === '::1') return runtimeHost();
  return host;
}
const port = Number(egress.port || 0);
if (!port) {
  return [{ json: { success: false, accepted: false, proxy_mode: 'US_RANDOM_DYNAMIC_IP', country_code: 'US', account_id: lease.account_id || input.account_id, lease_id: lease.lease_id || '', error_message: 'proxy-runtime dynamic IP lease has no egress endpoint' } }];
}
const scheme = endpointScheme(egress);
const host = endpointHost(egress);
return [{ json: {
  success: true,
  accepted: true,
  proxy_mode: 'US_RANDOM_DYNAMIC_IP',
  country_code: 'US',
  account_id: lease.account_id || input.account_id,
  lease_id: lease.lease_id || '',
  provider_account_id: lease.provider_account_id || '',
  proxy_url: `${scheme}://${host}:${port}`,
} }];
